class Engines {
    String node;

    Engines({
        required this.node,
    });

    factory Engines.fromJson(Map<String, dynamic> json) => Engines(
        node: json["node"],
    );

    Map<String, dynamic> toJson() => {
        "node": node,
    };
}

class Exports {
    List<dynamic> empty;
    List<String> browser;

    Exports({
        required this.empty,
        required this.browser,
    });

    factory Exports.fromJson(Map<String, dynamic> json) => Exports(
        empty: List<dynamic>.from(json["."].map((x) => x)),
        browser: List<String>.from(json["./browser"].map((x) => x)),
    );

    Map<String, dynamic> toJson() => {
        ".": List<dynamic>.from(empty.map((x) => x)),
        "./browser": List<dynamic>.from(browser.map((x) => x)),
    };
}

